//! Tag methods (metamethods) â€” ported from `ltm.c` / `ltm.h`.
//!
//! Every metamethod name (`__index`, `__add`, â€¦) is interned on `GlobalState`
//! during `init()`.  Lookup helpers (`get_tm`, `get_tm_by_obj`) return
//! `LuaValue::Nil` when no metamethod is present; callers check with
//! `value.is_nil()` (the `notm` macro in C).

use crate::state::LuaState;
#[allow(unused_imports)] use crate::prelude::*;
use lua_types::{CallInfoIdx, GcRef, LuaError, LuaType, LuaValue, StackIdx};

// â”€â”€ TagMethod enum (from ltm.h `TMS`) â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€

/// Metamethod selector; one variant per `__xxx` event, in ORDER TM.
///
/// The discriminant values are load-bearing: they index into
/// `GlobalState.tmname` and are used as bit positions in `Table.flags`.
/// Do **not** reorder without grepping ORDER TM / ORDER OP.
///
/// C: `typedef enum { TM_INDEX, â€¦ TM_N } TMS;`
#[derive(Debug, Clone, Copy, PartialEq, Eq, PartialOrd, Ord)]
#[repr(u8)]
pub(crate) enum TagMethod {
    // C: TM_INDEX
    Index = 0,
    // C: TM_NEWINDEX
    NewIndex,
    // C: TM_GC
    Gc,
    // C: TM_MODE
    Mode,
    // C: TM_LEN
    Len,
    // C: TM_EQ  /* last tag method with fast access */
    Eq,
    // C: TM_ADD
    Add,
    // C: TM_SUB
    Sub,
    // C: TM_MUL
    Mul,
    // C: TM_MOD
    Mod,
    // C: TM_POW
    Pow,
    // C: TM_DIV
    Div,
    // C: TM_IDIV
    IDiv,
    // C: TM_BAND
    BAnd,
    // C: TM_BOR
    BOr,
    // C: TM_BXOR
    BXor,
    // C: TM_SHL
    Shl,
    // C: TM_SHR
    Shr,
    // C: TM_UNM
    Unm,
    // C: TM_BNOT
    BNot,
    // C: TM_LT
    Lt,
    // C: TM_LE
    Le,
    // C: TM_CONCAT
    Concat,
    // C: TM_CALL
    Call,
    // C: TM_CLOSE
    Close,
    // C: TM_N  /* number of elements in the enum */
    N,
}

impl TagMethod {
    /// Convert a raw u8 discriminant to a `TagMethod`.
    /// Returns `TagMethod::N` (sentinel) if `v >= TM_N`.
    ///
    /// C: `cast(TMS, x)` â€” direct integer cast to the enum.
    /// PORT NOTE: reshaped for borrowck â€” C casts freely; Rust requires an explicit map.
    pub(crate) fn from_u8(v: u8) -> Self {
        match v {
            0  => TagMethod::Index,
            1  => TagMethod::NewIndex,
            2  => TagMethod::Gc,
            3  => TagMethod::Mode,
            4  => TagMethod::Len,
            5  => TagMethod::Eq,
            6  => TagMethod::Add,
            7  => TagMethod::Sub,
            8  => TagMethod::Mul,
            9  => TagMethod::Mod,
            10 => TagMethod::Pow,
            11 => TagMethod::Div,
            12 => TagMethod::IDiv,
            13 => TagMethod::BAnd,
            14 => TagMethod::BOr,

